function solve(nums) {
    const N = nums.length;
    if (N === 0) return 0;

    // --- Step 1: Preprocessing Positions Map ---
    // Positions[v] stores a sorted list of indices k where nums[k] = v.
    const positions = new Map();
    for (let i = 0; i < N; i++) {
        const v = nums[i];
        if (!positions.has(v)) {
            positions.set(v, []);
        }
        positions.get(v).push(i);
    }

    // Helper function for binary search (finding smallest index >= target)
    const lowerBound = (arr, target) => {
        let low = 0;
        let high = arr.length;
        while (low < high) {
            const mid = Math.floor((low + high) / 2);
            if (arr[mid] < target) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        return low;
    };

    // --- Step 2: Preprocessing Range OR Query (ROQ) using Sparse Table ---
    const LOGN = Math.floor(Math.log2(N)) + 1;
    // ST[k][i] = OR of subarray starting at i of length 2^k
    const ST = Array(LOGN).fill(0).map(() => Array(N).fill(0));

    for (let i = 0; i < N; i++) {
        ST[0][i] = nums[i];
    }

    for (let k = 1; k < LOGN; k++) {
        for (let i = 0; i + (1 << k) <= N; i++) {
            ST[k][i] = ST[k - 1][i] | ST[k - 1][i + (1 << (k - 1))];
        }
    }

    // Query OR(i, j) = OR of nums[i] through nums[j] inclusive
    const queryOR = (i, j) => {
        if (i > j) return 0;
        const length = j - i + 1;
        const k = Math.floor(Math.log2(length));
        return ST[k][i] | ST[k][j - (1 << k) + 1];
    };

    // --- Step 3: Main Calculation ---
    let totalGoodSubarrays = 0;

    for (let i = 0; i < N; i++) {
        let current_j_start = i;
        let current_or = 0;

        while (current_j_start < N) {
            // 1. Determine the OR value V for the current segment [current_j_start, j_end]
            // Since we are iterating i, current_or needs to be correctly established for the starting point
            if (current_j_start === i) {
                current_or = nums[i];
            } else {
                // If we jumped segments, we need the OR of nums[i]..nums[current_j_start - 1] | nums[current_j_start]
                // Since the segments are defined such that the OR is constant, we can just rely on the segment calculation
                // For robustness, we recalculate the OR up to current_j_start to ensure consistency.
                current_or = queryOR(i, current_j_start);
            }
            const V = current_or;

            // 2. Find j_end: the largest index >= current_j_start such that OR(i, j_end) == V
            let low = current_j_start;
            let high = N - 1;
            let j_end = current_j_start;

            // Binary search to find the boundary where OR changes from V
            while (low <= high) {
                const mid = Math.floor((low + high) / 2);
                if (queryOR(i, mid) === V) {
                    j_end = mid;
                    low = mid + 1; // Try to go further right
                } else {
                    high = mid - 1; // OR already exceeded V, must stop earlier
                }
            }

            // The segment is [current_j_start, j_end] with OR value V.

            // 3. Calculate count for this segment
            let countSegment = 0;
            const positionsV = positions.get(V);

            if (positionsV) {
                // Find P: the first index k >= i such that nums[k] = V
                let p_index_in_list = lowerBound(positionsV, i);

                if (p_index_in_list < positionsV.length) {
                    const P = positionsV[p_index_in_list]; // The actual index of first occurrence >= i

                    if (P < current_j_start) {
                        // V was already present in nums[i...current_j_start - 1]
                        countSegment = j_end - current_j_start + 1;
                    } else if (P <= j_end) {
                        // V first appears at P, and P is within the segment [current_j_start, j_end]
                        // It contributes to good subarrays from P to j_end
                        countSegment = j_end - P + 1;
                    } 
                    // If P > j_end, countSegment remains 0, as V hasn't appeared yet in this range.
                }
            }

            totalGoodSubarrays += countSegment;

            // 4. Move to the next segment
            current_j_start = j_end + 1;
        }
    }

    return totalGoodSubarrays;
}

