import scala.collection.mutable
import scala.math.log
import scala.math.ceil

object Solution {
    /**
     * Finds the smallest index k in the sorted list arr such that arr[k] >= target.
     * Returns arr.length if no such element exists.
     */
    def lowerBound[T: Ordering](arr: Seq[T], target: T): Int = {
        var low = 0
        var high = arr.length
        while (low < high) {
            val mid = low + (high - low) / 2
            if (arr(mid) < target) {
                low = mid + 1
            } else {
                high = mid
            }
        }
        low
    }

    def solve(nums: Array[Long]): Long = {
        val N = nums.length
        if (N == 0) return 0L

        // --- Step 1: Preprocessing Positions Map ---
        // positions[v] stores a sorted list of indices k where nums[k] = v.
        val positions = mutable.HashMap[Long, Seq[Int]]()
        for (i <- 0 until N) {
            val v = nums(i)
            positions.getOrElseUpdate(v, Seq.empty[Int]) = positions(v) :+ i
        }

        // --- Step 2: Preprocessing Range OR Query (ROQ) using Sparse Table ---
        val LOGN = (log(N.toDouble) / log(2.0)).ceil.toInt + 1

        // ST[k][i] = OR of subarray starting at i of length 2^k
        // We use Array(Array) structure for ST
        var ST: Array[Array[Long]] = Array.fill(0)(Array.fill(0)(0L))

        // Base case k=0 (length 2^0 = 1)
        for (i <- 0 until N) {
            ST(0)(i) = nums(i)
        }

        // Build the table
        for (k <- 1 until LOGN) {
            val halfLen = 1 << (k - 1)
            for (i <- 0 until N - (1 << k) + 1) {
                ST(k)(i) = ST(k - 1)(i) | ST(k - 1)(i + halfLen)
            }
        }

        // Helper function for Range OR Query (ROQ)
        def queryOR(i: Int, j: Int): Long = {
            if (i > j) return 0L
            val length = j - i + 1
            val k = (log(length.toDouble) / log(2.0)).floor.toInt
            val powerOf2k = 1 << k

            ST(k)(i) | ST(k)(j - powerOf2k + 1)
        }

        // --- Step 3: Main Calculation ---
        var totalGoodSubarrays: Long = 0L

        for (i <- 0 until N) {
            var current_j_start = i

            // Segment decomposition loop starting from i
            while (current_j_start < N) {
                // 1. Determine the OR value V for the segment starting at current_j_start
                // V = OR(nums[i...current_j_start])
                val V = queryOR(i, current_j_start)

                // 2. Find j_end: the largest index >= current_j_start such that OR(i, j_end) == V
                var low = current_j_start
                var high = N - 1
                var j_end = current_j_start

                // Binary search to find the boundary where OR changes from V
                while (low <= high) {
                    val mid = low + (high - low) / 2
                    if (queryOR(i, mid) == V) {
                        j_end = mid
                        low = mid + 1 // Try to go further right
                    } else {
                        high = mid - 1 // OR already exceeded V, must stop earlier
                    }
                }

                // The segment is [current_j_start, j_end] where OR(i, r) = V for r in this segment.

